update exam_assignment_answer set score = CASE
WHEN submission_id = #{item.submissionId} AND question_id = #{item.questionId} THEN #{item.score}
ELSE score END, feedback = CASE
WHEN submission_id = #{item.submissionId} AND question_id = #{item.questionId} THEN #{item.feedback}
ELSE feedback END, update_time = now() where (submission_id, question_id) in
(#{item.submissionId}, #{item.questionId})
